const body = $json.body;
const name = (body.client_name || '').trim();
const matter_id = (body.matter_id || '').trim();
const binaryKeys = Object.keys($binary || {});

if (!name) throw new Error('Client name is required');
if (!matter_id) throw new Error('Matter ID is required');
if (binaryKeys.length === 0) throw new Error('No PDF file uploaded');

return {
  json: {
    client_name: name,
    matter_id: matter_id,
    case_id: 'RL-' + Date.now(),
    binary_key: binaryKeys[0],
    CLIO_API_BASE: $json.CLIO_API_BASE,
    VERIFY_PAGE_URL: $json.VERIFY_PAGE_URL,
    PARALEGAL_EMAIL: $json.PARALEGAL_EMAIL,
    WORKFLOW_B_ID: $json.WORKFLOW_B_ID
  },
  binary: $binary
};

