={
  "model": "claude-sonnet-4-6",
  "max_tokens": 1500,
  "system": "You are a legal data extraction specialist. Return ONLY valid JSON, no markdown fencing. Dates in YYYY-MM-DD format. null for absent fields.",
  "messages": [{
    "role": "user",
    "content": [
      {
        "type": "document",
        "source": { "type": "base64", "media_type": "application/pdf", "data": "{{ $json.data }}" }
      },
      {
        "type": "text",
        "text": "Extract these fields from this police report as JSON: client_name (LASTNAME, FIRSTNAME format), date_of_accident (YYYY-MM-DD), defendant_name (LASTNAME, FIRSTNAME format), accident_location (full location with cross streets, county, borough, state), client_vehicle_plate (license plate number and state, null if pedestrian/cyclist), number_of_injured (integer), accident_description (2-3 sentences, third person, factual), client_sex (M or F), confidence_score (1-10 how confident you are in the extraction), confidence_notes (brief note on any unclear fields)"
      }
    ]
  }]
}

