let raw = $json.content[0].text;
raw = raw.replace(/^```json?\s*/i, '').replace(/\s*```$/i, '').trim();
const extracted = JSON.parse(raw);
const accDate = new Date(extracted.date_of_accident);
const solDate = new Date(accDate);
solDate.setFullYear(solDate.getFullYear() + 8);
const sol_date = solDate.toISOString().split('T')[0];
const config = $('Config').item.json;
const input = $('Validate Input').item.json;
return {
  ...extracted,
  sol_date: sol_date,
  matter_id: input.matter_id,
  case_id: input.case_id,
  CLIO_API_BASE: config.CLIO_API_BASE,
  VERIFY_PAGE_URL: config.VERIFY_PAGE_URL,
  PARALEGAL_EMAIL: config.PARALEGAL_EMAIL,
  WORKFLOW_B_ID: config.WORKFLOW_B_ID
};

const verified = $json;
const accDate = new Date(verified.date_of_accident);
const solDate = new Date(accDate);
solDate.setFullYear(solDate.getFullYear() + 8);
const sol_date = solDate.toISOString().split('T')[0];
const sex = (verified.client_sex || 'M').trim().toUpperCase();
const pronoun_possessive = sex === 'F' ? 'her' : 'his';
const pronoun_subject = sex === 'F' ? 'she' : 'he';
const pronoun_object = sex === 'F' ? 'her' : 'him';
const matter_id = $('Validate Input').item.json.matter_id;
const case_id = $('Validate Input').item.json.case_id;
const config = $('Config').item.json;
return {
  ...verified,
  sol_date: sol_date,
  matter_id: matter_id,
  case_id: case_id,
  pronoun_possessive: pronoun_possessive,
  pronoun_subject: pronoun_subject,
  pronoun_object: pronoun_object,
  CLIO_API_BASE: config.CLIO_API_BASE,
  WORKFLOW_B_ID: config.WORKFLOW_B_ID
};
